  1→import React, {useMemo, useState} from 'react';
  2→import {
  3→  FlatList,
  4→  Pressable,
  5→  ScrollView,
  6→  StyleSheet,
  7→  Text,
  8→  View,
  9→} from 'react-native';
 10→import {useInfiniteQuery, useMutation} from '@tanstack/react-query';
 11→import {BottomTabScreenProps} from '@react-navigation/bottom-tabs';
 12→import {CompositeScreenProps} from '@react-navigation/native';
 13→import {NativeStackScreenProps} from '@react-navigation/native-stack';
 14→import {SafeAreaView} from 'react-native-safe-area-context';
 15→import {PostCard} from '../../components/PostCard/PostCard';
 16→import {PostCardSkeleton} from '../../components/SkeletonLoader';
 17→import {CommentModal} from '../../components/Comments';
 18→import {RepostModal} from '../../components/RepostModal';
 19→import {Chip} from '../../components/Chip';
 20→import {EmptyState} from '../../components/EmptyState';
 21→import {PenIcon} from '../../components/icons';
 22→import {useAuth} from '../../features/auth/AuthProvider';
 23→import {useTheme} from '../../theme/ThemeProvider';
 24→import {fonts, typeScale} from '../../theme/typography';
 25→import {spacing, radii, shadows} from '../../theme/spacing';
 26→import {
 27→  mobileApi,
 28→  type CursorPage,
 29→  type JournalItem,
 30→} from '../../lib/api/mobileApi';
 31→import {socialApi} from '../../lib/api/socialApi';
 32→import {queryClient} from '../../lib/queryClient';
 33→import {useBookmarkMutation} from '../../hooks/useSocialMutations';
 34→import {
 35→  extractPlainText,
 36→  extractBannerImage,
 37→  resolveCount,
 38→  getNextCursor,
 39→} from '../../lib/utils/journalHelpers';
 40→import type {MainTabParamList, RootStackParamList} from '../../navigation/types';
 41→
 42→type Props = CompositeScreenProps<
 43→  BottomTabScreenProps<MainTabParamList, 'Home'>,
 44→  NativeStackScreenProps<RootStackParamList>
 45→>;
 46→
 47→const PAGE_SIZE = 10;
 48→
 49→const QUICK_ACTIONS = [
 50→  {key: 'all', label: 'All'},
 51→  {key: 'journal', label: 'Journals'},
 52→] as const;
 53→
 54→export function HomeFeedScreen({navigation}: Props) {
 55→  const {user, session} = useAuth();
 56→  const {colors} = useTheme();
 57→  const token = session?.access_token ?? '';
 58→  const [refreshing, setRefreshing] = useState(false);
 59→  const [activeFilter, setActiveFilter] = useState('all');
 60→  const [commentModal, setCommentModal] = useState<{postId: string; receiverId?: string; commentCount: number} | null>(null);
 61→  const [repostModal, setRepostModal] = useState<{journalId: string; title?: string; authorName?: string; authorAvatar?: string} | null>(null);
 62→
 63→  const feedQuery = useInfiniteQuery({
 64→    queryKey: ['feed', user?.id],
 65→    queryFn: ({pageParam}) =>
 66→      mobileApi.getJournals(pageParam ?? null, PAGE_SIZE, user?.id),
 67→    initialPageParam: null as string | null,
 68→    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
 69→  });
 70→
 71→  const reactionMutation = useMutation({
 72→    mutationFn: async ({
 73→      journalId,
 74→      receiverId,
 75→      reactionType,
 76→    }: {
 77→      journalId: string;
 78→      receiverId: string;
 79→      reactionType: string;
 80→    }) => {
 81→      if (!token) throw new Error('Please log in to react.');
 82→      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
 83→    },
 84→    onMutate: async ({journalId, reactionType}) => {
 85→      await queryClient.cancelQueries({queryKey: ['feed']});
 86→      const prev = queryClient.getQueryData<{pages: CursorPage<JournalItem>[]}>(
 87→        ['feed', user?.id],
 88→      );
 89→      if (prev) {
 90→        queryClient.setQueryData<{pages: CursorPage<JournalItem>[]}>(
 91→          ['feed', user?.id],
 92→          old => {
 93→            if (!old) return old;
 94→            return {
 95→              ...old,
 96→              pages: old.pages.map(page => ({
 97→                ...page,
 98→                data: page.data.map(item => {
 99→                  if (item.id !== journalId) return item;
100→                  const removing = item.user_reaction === reactionType;
101→                  const currentCount =
102→                    (item.reaction_count?.[0]?.count ??
103→                      item.like_count?.[0]?.count ??
104→                      item.likes_count ??
105→                      0) as number;
106→                  const delta = removing ? -1 : item.user_reaction ? 0 : 1;
107→                  return {
108→                    ...item,
109→                    user_reaction: removing ? null : reactionType,
110→                    has_liked: removing ? false : true,
111→                    like_count: [{count: Math.max(0, currentCount + delta)}],
112→                  };
113→                }),
114→              })),
115→            };
116→          },
117→        );
118→      }
119→      return {prev};
120→    },
121→    onError: (_err, _vars, context) => {
122→      if (context?.prev) {
123→        queryClient.setQueryData(['feed', user?.id], context.prev);
124→      }
125→    },
126→    onSettled: () => {
127→      queryClient.invalidateQueries({queryKey: ['feed']});
128→    },
129→  });
