  journalId: string;
  title?: string;
  authorName?: string;
  authorAvatar?: string;
} | null>(null);

const normalizedQuery = useMemo(() => query.trim(), [query]);
const isSearching = normalizedQuery.length >= 2;
```

### How Search API Calls Are Made
Both use `useQuery` from `@tanstack/react-query`. They are conditionally enabled via the `enabled` flag:

```typescript
const usersQuery = useQuery({
  queryKey: ['search-users', normalizedQuery],
  enabled: isSearching && activeTab !== 'posts',
  queryFn: () => mobileApi.searchUsers(normalizedQuery, 10),
});

const journalsQuery = useQuery({
  queryKey: ['search-journals', normalizedQuery],
  enabled: isSearching && activeTab !== 'users',
  queryFn: () => mobileApi.searchJournals(normalizedQuery, 10),
});

const users = usersQuery.data?.data ?? [];
const journals = journalsQuery.data?.data ?? [];
```

No `useEffect` or debounce — the query key includes `normalizedQuery` so React Query re-fetches automatically when it changes. There is no debouncing or minimum character delay beyond `isSearching = normalizedQuery.length >= 2`.

### Exact Query Key Patterns
| Query | Key |
|---|---|
| Hottest monthly | `['explore-hottest-monthly', user?.id]` |
| User search | `['search-users', normalizedQuery]` |
| Journal search | `['search-journals', normalizedQuery]` |

